
  CREATE TABLE "DIRKSPZM32"."TMS_LOADING_CARRIER" 
   (	"SID" VARCHAR2(2 CHAR) NOT NULL ENABLE, 
	"FIRMA_NR" NUMBER(6,0) NOT NULL ENABLE, 
	"LOADING_CARRIER_ID" VARCHAR2(30 CHAR) NOT NULL ENABLE, 
