	"TARA" NUMBER(*,6), 
	"ZOLLPLOMBE_ID" VARCHAR2(20 CHAR)
   ) ;
ALTER TABLE "DIRKSPZM32"."TMS_LOADING_CARRIER" ADD CONSTRAINT "PK_TMS_LOADING_CARRIER" PRIMARY KEY ("LOADING_CARRIER_ID", "ARRIVAL_TIME", "FIRMA_NR", "SID")
  USING INDEX  ENABLE;
ALTER TABLE "DIRKSPZM32"."TMS_LOADING_CARRIER" ADD CONSTRAINT "TMS_LOADING_CARRIER_TYP_C" CHECK (LOADING_CARRIER_TYP in ('CONTAINER', 'LKW')) ENABLE;


